                  </div>
                ))}
              </div>
            </div>

            <div className="w-full max-w-3xl py-10 space-y-16">
              <h3 className="text-center text-[10px] font-black text-teal-500 tracking-[0.4em] uppercase">进化路径 / Evolution</h3>
